-- Italian B1
VALUES ('aabbccdd-4444-0000-0000-b10000000000', 'en', 'it', 'Italian B1', 'Italian course - CEFR B1', 8, true, 'B1');

VALUES ('aabbccdd-4444-3001-0000-b10000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'Opinions & Current Events', 'Agree/disagree, news, society', 0, 6);

VALUES ('aabbccdd-4444-3002-0000-b10000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'Work & Career', 'Interviews, meetings, emails, presentations', 1, 6);

VALUES ('aabbccdd-4444-3003-0000-b10000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'Travel & Adventure', 'Booking, airports, hotels, experiences', 2, 6);

VALUES ('aabbccdd-4444-3004-0000-b10000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'Environment & Nature', 'Climate, animals, conservation', 3, 6);

VALUES ('aabbccdd-4444-3005-0000-b10000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'Technology & Media', 'Internet, social media, devices', 4, 6);

VALUES ('aabbccdd-4444-3006-0000-b10000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'Storytelling', 'Narrative tenses, sequencing, past continuous', 5, 6);

VALUES ('aabbccdd-4444-3007-0000-b10000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'Hypothetical Situations', 'Conditionals, would/could/should', 6, 6);

VALUES ('aabbccdd-4444-3008-0000-b10000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'Formal vs. Informal', 'Register, polite requests, slang', 7, 6);
VALUES ('aabbccdd-4444-3001-a001-000000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'aabbccdd-4444-3001-0000-b10000000000', 'B1', 'El cambio climatico', 'El cambio climatico es uno de los problemas mas importantes de nuestro tiempo. Las temperaturas globales estan subiendo, los glaciares se derriten y el nivel del mar aumenta. Los cientificos dicen que debemos reducir las emisiones de carbono para proteger nuestro planeta. Muchos paises estan adoptando energias renovables como la solar y la eolica. Cada persona puede contribuir reciclando, usando transporte publico y ahorrando energia en casa.', 150, true);
VALUES ('aabbccdd-4444-3002-a001-000000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'aabbccdd-4444-3002-0000-b10000000000', 'B1', 'La entrevista de trabajo', 'Maria tiene una entrevista de trabajo manana. Ella ha preparado su curriculum y ha investigado sobre la empresa. Se siente nerviosa pero emocionada. Su amiga le aconseja que llegue temprano, vista de manera profesional y sea honesta con sus respuestas. Maria practica respondiendo preguntas comunes como: Cuales son sus fortalezas? y Por que quiere trabajar aqui? Ella espera conseguir el puesto.', 120, true);
VALUES ('aabbccdd-4444-3003-a001-000000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'aabbccdd-4444-3003-0000-b10000000000', 'B1', 'Viaje a Barcelona', 'El verano pasado, mi familia y yo viajamos a Barcelona. Reservamos un hotel cerca de la playa y visitamos la Sagrada Familia, el Parque Guell y Las Ramblas. La comida fue increible, especialmente la paella y las tapas. Tambien aprendimos algunas palabras en catalan. El viaje duro una semana y fue una experiencia inolvidable. Espero volver el proximo ano.', 100, true);
VALUES ('aabbccdd-4444-3004-a001-000000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'aabbccdd-4444-3004-0000-b10000000000', 'B1', 'La tecnologia en la educacion', 'Hoy en dia, la tecnologia juega un papel importante en la educacion. Los estudiantes usan tablets y computadoras en clase. Las aplicaciones de aprendizaje hacen que estudiar sea mas interactivo y divertido. Sin embargo, algunos expertos se preocupan por el tiempo excesivo frente a las pantallas. Es importante encontrar un equilibrio entre la tecnologia y los metodos tradicionales de ensenanza.', 110, true);
VALUES ('aabbccdd-4444-3005-a001-000000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'aabbccdd-4444-3005-0000-b10000000000', 'B1', 'El medio ambiente', 'La contaminacion es un problema serio en muchas ciudades. El aire sucio causa problemas de salud, especialmente para los ninos y las personas mayores. Para combatir la contaminacion, algunas ciudades han implementado zonas sin coches y promueven el uso de bicicletas. Tambien es importante plantar mas arboles y reducir el uso de plastico. Todos debemos hacer nuestra parte para proteger el medio ambiente.', 110, true);
VALUES ('aabbccdd-4444-3006-a001-000000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'aabbccdd-4444-3006-0000-b10000000000', 'B1', 'Las redes sociales', 'Las redes sociales han cambiado la forma en que nos comunicamos. Podemos conectar con personas de todo el mundo, compartir fotos y noticias al instante. Sin embargo, tambien hay desventajas como la desinformacion, el ciberacoso y la adiccion. Es importante usar las redes sociales de manera responsable y verificar la informacion antes de compartirla.', 100, true);
VALUES ('aabbccdd-4444-3007-a001-000000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'aabbccdd-4444-3007-0000-b10000000000', 'B1', 'Cocina internacional', 'La comida es una parte importante de la cultura. Cada pais tiene sus platos tipicos. En Espana, la paella es famosa. En Italia, la pasta y la pizza. En Japon, el sushi y el ramen. Probar comida de otros paises es una manera deliciosa de aprender sobre diferentes culturas. Hoy en dia, es facil encontrar restaurantes internacionales en casi cualquier ciudad.', 100, true);
VALUES ('aabbccdd-4444-3008-a001-000000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'aabbccdd-4444-3008-0000-b10000000000', 'B1', 'El deporte y la salud', 'Hacer ejercicio regularmente es esencial para mantener una buena salud. Los expertos recomiendan al menos treinta minutos de actividad fisica al dia. Caminar, nadar, correr o andar en bicicleta son opciones excelentes. El ejercicio no solo mejora la salud fisica, sino tambien la salud mental. Reduce el estres, mejora el sueno y aumenta la energia.', 100, true);
VALUES ('aabbccdd-4444-3001-d001-000000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'aabbccdd-4444-3001-0000-b10000000000', 'B1', 'Write about your daily routine. Include: what time you wake up, what you eat for breakfast, how you get to work or school, and what you do in the evening. Use at least 80 words.', 'guided', 80, 150);
VALUES ('aabbccdd-4444-3002-d001-000000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'aabbccdd-4444-3002-0000-b10000000000', 'B1', 'Describe your ideal vacation. Where would you go? Who would you travel with? What activities would you do? Write at least 80 words.', 'guided', 80, 150);
VALUES ('aabbccdd-4444-3003-d001-000000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'aabbccdd-4444-3003-0000-b10000000000', 'B1', 'Write an email to a friend inviting them to visit your city. Recommend places to see and things to do. Use formal greetings and closings.', 'guided', 80, 150);
VALUES ('aabbccdd-4444-3004-d001-000000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'aabbccdd-4444-3004-0000-b10000000000', 'B1', 'Describe a memorable experience from your childhood. What happened? How did you feel? Why is it memorable? Use past tenses.', 'guided', 80, 150);
VALUES ('aabbccdd-4444-3005-d001-000000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'aabbccdd-4444-3005-0000-b10000000000', 'B1', 'Write about the advantages and disadvantages of social media. Give at least two of each. Express your personal opinion.', 'guided', 80, 150);
VALUES ('aabbccdd-4444-3006-d001-000000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'aabbccdd-4444-3006-0000-b10000000000', 'B1', 'Describe your favorite book or movie. What is it about? Why do you like it? Would you recommend it? Explain why.', 'guided', 80, 150);
VALUES ('aabbccdd-4444-3007-d001-000000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'aabbccdd-4444-3007-0000-b10000000000', 'B1', 'Write about what you would do if you won the lottery. Use conditional tenses. Mention at least three things.', 'guided', 80, 150);
VALUES ('aabbccdd-4444-3008-d001-000000000000', 'aabbccdd-4444-0000-0000-b10000000000', 'aabbccdd-4444-3008-0000-b10000000000', 'B1', 'Write a letter of complaint to a hotel about a bad experience during your stay. Be polite but firm. Describe the problems and request a solution.', 'guided', 80, 150);

